package main

import (
    "fmt"
    "io"
    "net/http"
    "time"
)

func main() {
    // ---- Basic GET request ----
    fmt.Println("=== GET Request ===")

    resp, err := http.Get("https://httpbin.org/ip")
    if err != nil {
        fmt.Println("Error:", err)
        return
    }
    defer resp.Body.Close()

    body, err := io.ReadAll(resp.Body)
    if err != nil {
        fmt.Println("Error:", err)
        return
    }

    fmt.Println("Status:", resp.Status)
    fmt.Println("Body:", string(body))

    // ---- GET with custom client ----
    fmt.Println("\n=== GET with Custom Client ===")

    client := &http.Client{
        Timeout: 5 * time.Second,
    }

    req, err := http.NewRequest("GET", "https://httpbin.org/user-agent", nil)
    if err != nil {
        fmt.Println("Error:", err)
        return
    }

    req.Header.Set("User-Agent", "Go-chan Bot")

    resp2, err := client.Do(req)
    if err != nil {
        fmt.Println("Error:", err)
        return
    }
    defer resp2.Body.Close()

    body2, err := io.ReadAll(resp2.Body)
    if err != nil {
        fmt.Println("Error:", err)
        return
    }

    fmt.Println("Status:", resp2.Status)
    fmt.Println("Body:", string(body2))

    // ---- GET with query parameters ----
    fmt.Println("\n=== GET with Query Parameters ===")

    req3, err := http.NewRequest("GET", "https://httpbin.org/get", nil)
    if err != nil {
        fmt.Println("Error:", err)
        return
    }

    q := req3.URL.Query()
    q.Add("page", "1")
    q.Add("limit", "10")
    req3.URL.RawQuery = q.Encode()

    resp3, err := client.Do(req3)
    if err != nil {
        fmt.Println("Error:", err)
        return
    }
    defer resp3.Body.Close()

    body3, err := io.ReadAll(resp3.Body)
    if err != nil {
        fmt.Println("Error:", err)
        return
    }

    fmt.Println("Query Response:")
    fmt.Println(string(body3))

    // ---- POST request ----
    fmt.Println("\n=== POST Request ===")

    // In a real app, you'd use strings.NewReader or bytes.Buffer
    // For this example, we'll use a simple POST

    req4, err := http.NewRequest("POST", "https://httpbin.org/post", nil)
    if err != nil {
        fmt.Println("Error:", err)
        return
    }

    req4.Header.Set("Content-Type", "application/json")

    resp4, err := client.Do(req4)
    if err != nil {
        fmt.Println("Error:", err)
        return
    }
    defer resp4.Body.Close()

    body4, err := io.ReadAll(resp4.Body)
    if err != nil {
        fmt.Println("Error:", err)
        return
    }

    fmt.Println("POST Response:")
    fmt.Println(string(body4))
}

